css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0a0a14; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(99,102,241,0.15); }
.logo { font-size: 20px; font-weight: 800; color: #818cf8; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.platforms { display: flex; gap: 8px; }
.pl-btn { padding: 8px 16px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: white; font-size: 13px; font-weight: 600; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 72px); }
.tag { color: #818cf8; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 20px; }
h1 { font-size: 72px; font-weight: 900; line-height: 0.95; letter-spacing: -3px; margin-bottom: 20px; } h1 span { color: #818cf8; }
.hero-left p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 28px; }
.listen-btns { display: flex; gap: 12px; margin-bottom: 36px; }
.btn-spotify { padding: 14px 24px; border-radius: 30px; border: none; background: #1db954; color: white; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-apple { padding: 14px 24px; border-radius: 30px; border: 1px solid rgba(255,255,255,0.2); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.stats-row { display: flex; gap: 32px; } .stat strong { display: block; font-size: 28px; font-weight: 900; color: #818cf8; } .stat span { color: #4b5563; font-size: 13px; }
.player-card { background: rgba(99,102,241,0.08); border: 1px solid rgba(99,102,241,0.3); border-radius: 24px; padding: 28px; text-align: center; }
.pc-badge { display: inline-block; background: #6366f1; color: white; padding: 4px 14px; border-radius: 20px; font-size: 11px; font-weight: 800; margin-bottom: 20px; animation: pulse 2s infinite; }
@keyframes pulse { 0%,100%{opacity:1}50%{opacity:0.6} }
.pc-cover { width: 120px; height: 120px; border-radius: 20px; background: linear-gradient(135deg, #4338ca, #7c3aed); display: flex; align-items: center; justify-content: center; font-size: 48px; margin: 0 auto 20px; box-shadow: 0 20px 40px rgba(99,102,241,0.3); }
.pc-title { font-size: 17px; font-weight: 700; margin-bottom: 4px; }
.pc-ep { color: #6b7280; font-size: 13px; margin-bottom: 20px; }
.pp-bar { height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; margin-bottom: 8px; cursor: pointer; } .pp-fill { height: 100%; border-radius: 2px; background: #6366f1; width: 35%; transition: width 0.1s; }
.pp-time { display: flex; justify-content: space-between; font-size: 11px; color: #6b7280; margin-bottom: 20px; }
.pc-controls { display: flex; justify-content: center; align-items: center; gap: 16px; }
.pc-controls button { background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.1); color: white; border-radius: 20px; padding: 8px 16px; font-size: 13px; cursor: pointer; }
.play-btn { width: 52px; height: 52px; border-radius: 50% !important; background: #6366f1 !important; border-color: #6366f1 !important; font-size: 18px !important; padding: 0 !important; }
.episodes { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); }
.episodes h2 { font-size: 36px; font-weight: 800; margin-bottom: 28px; }
.ep-list { display: flex; flex-direction: column; gap: 0; }
.ep-item { display: flex; align-items: center; gap: 20px; padding: 20px 0; border-bottom: 1px solid rgba(255,255,255,0.06); cursor: pointer; transition: all 0.2s; } .ep-item:hover { padding-left: 8px; }
.ep-num { width: 48px; height: 48px; border-radius: 12px; background: rgba(99,102,241,0.15); border: 1px solid rgba(99,102,241,0.3); display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 800; color: #818cf8; flex-shrink: 0; }
.ep-info { flex: 1; } .ep-info strong { display: block; font-size: 16px; font-weight: 700; margin-bottom: 4px; } .ep-info span { color: #6b7280; font-size: 13px; }
.ep-play { width: 40px; height: 40px; border-radius: 50%; border: 1px solid rgba(99,102,241,0.4); background: rgba(99,102,241,0.1); color: #818cf8; font-size: 14px; cursor: pointer; transition: all 0.2s; } .ep-play:hover { background: #6366f1; color: white; }

