let playing = true, progress = 35, secs = 1104;
const fill = document.getElementById('fill');
const btn = document.getElementById('play-btn');
const cur = document.getElementById('current');
let interval = setInterval(tick, 1000);
function tick() { if (!playing) return; secs++; progress = Math.min((secs / 3120) * 100, 100); fill.style.width = progress + '%'; const m = Math.floor(secs/60), s = secs%60; cur.textContent = m + ':' + String(s).padStart(2,'0'); }
function togglePlay() { playing = !playing; btn.textContent = playing ? '⏸' : '▶'; }
function skip(s) { secs = Math.max(0, Math.min(secs + s, 3120)); const m = Math.floor(secs/60), sec = secs%60; cur.textContent = m + ':' + String(sec).padStart(2,'0'); progress = (secs/3120)*100; fill.style.width = progress + '%'; }
document.querySelectorAll('.ep-play').forEach(btn => { btn.addEventListener('click', function() { playing = true; document.getElementById('play-btn').textContent = '⏸'; }); });
